To fix the code and prevent Cross-Site Scripting (XSS) vulnerabilities, you need to properly sanitize the user input before outputting it to the response. One common approach is to escape special characters in the user input. Here's an updated version of the code that implements this security measure:

```java
import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Escape special characters in the user input
        String sanitizedInput = escapeHtml(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("User input: " + sanitizedInput);
        out.println("</body></html>");
    }

    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }
        return input.replaceAll("&", "&amp;")
                     .replaceAll("<", "&lt;")
                     .replaceAll(">", "&gt;")
                     .replaceAll("\"", "&quot;")
                     .replaceAll("'", "&#39;");
    }
}
``

